def is_balanced(s):
    stack = []
    matching = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack[-1] != matching[char]:
                return False
            stack.pop()
    return len(stack) == 0

# Run examples
tests = [
    ('()[]{}', True),
    ('([{}])', True),
    ('([)]',   False),
    ('{[}',    False),
    ('',       True),
]

all_passed = True
for s, expected in tests:
    result = is_balanced(s)
    status = '✓' if result == expected else '✗'
    if result != expected:
        all_passed = False
    print(f'{status}  is_balanced({s!r:10}) → {result}  (expected {expected})')

print()
print('All tests passed!' if all_passed else 'Some tests FAILED.')
"
